import redis
import json
import sys

class RedisLuaClient:
    def __init__(self, host='localhost', port=6379, db=0, password=None):
        self.client = redis.Redis(
            host=host,
            port=port,
            db=db,
            password=password,
            decode_responses=True
        )
    
    def execute_lua_script(self, script, keys=None, args=None):
        if keys is None:
            keys = []
        if args is None:
            args = []
        
        return self.client.eval(script, len(keys), *keys, *args)
    
    def execute_user_script(self, user_script, user_keys, user_args):
        return self.execute_lua_script(user_script, user_keys, user_args)
    
    def close(self):
        self.client.close()


